--
-- Name: update_delivered_at(); Type: FUNCTION; Schema: public; Owner: wateroms
--

CREATE FUNCTION public.update_delivered_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
        NEW.delivered_at := CURRENT_TIMESTAMP;
    END IF;
    RETURN NEW;
END;
$$;


