--
-- Name: update_inventory_on_delivery(); Type: FUNCTION; Schema: public; Owner: wateroms
--

CREATE FUNCTION public.update_inventory_on_delivery() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.status = 'completed' AND OLD.status != 'completed' THEN
        UPDATE product_inventory
        SET quantity = quantity - oi.actual_qty,
            updated_at = CURRENT_TIMESTAMP
        FROM order_item oi
        WHERE oi.order_id = NEW.id
          AND product_inventory.warehouse_id = NEW.warehouse_id
          AND product_inventory.product_id = oi.product_id;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_inventory_on_delivery() OWNER TO wateroms;

